provider "aws" {
  region = "ap-southeast-1"
}

resource "aws_s3_bucket" "primary_source_bucket" {
  bucket_prefix = "primary-source-"
}

resource "aws_s3_bucket" "secondary_source_one_bucket" {
  bucket_prefix = "secondary-source-one-"
}

resource "aws_s3_bucket" "secondary_source_two_bucket" {
  bucket_prefix = "secondary-source-two-"
}

resource "aws_s3_bucket" "artifact_bucket" {
  bucket_prefix = "artifact-"
}

data "aws_iam_policy_document" "codebuild_trust_policy" {
  statement {
    effect    = "Allow"
    actions   = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }
  }
}

resource "aws_iam_role" "codebuild_role" {
  name               = "example-codebuild-role"
  assume_role_policy = data.aws_iam_policy_document.codebuild_trust_policy.json
}

data "aws_iam_policy_document" "codebuild_permissions_policy" {
  statement {
    effect    = "Allow"
    actions   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
    resources = ["*"]
  }

  statement {
    effect = "Allow"
    actions = [
      "s3:GetObject",
      "s3:PutObject"
    ]
    resources = [
      "${aws_s3_bucket.primary_source_bucket.arn}/*",
      "${aws_s3_bucket.secondary_source_one_bucket.arn}/*",
      "${aws_s3_bucket.secondary_source_two_bucket.arn}/*",
      "${aws_s3_bucket.artifact_bucket.arn}/*"
    ]
  }

  statement {
    effect = "Allow"
    actions = [
      "s3:ListBucket"
    ]
    resources = [
      aws_s3_bucket.primary_source_bucket.arn,
      aws_s3_bucket.secondary_source_one_bucket.arn,
      aws_s3_bucket.secondary_source_two_bucket.arn,
      aws_s3_bucket.artifact_bucket.arn
    ]
  }
}

resource "aws_iam_policy" "codebuild_policy" {
  name   = "example-codebuild-policy"
  policy = data.aws_iam_policy_document.codebuild_permissions_policy.json
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

resource "aws_codebuild_project" "example" {
  name         = "example-codebuild-project"
  service_role = aws_iam_role.codebuild_role.arn

  source {
    buildspec = "version: 0.2\nphases:\n  build:\n    commands:\n      - echo 'Hello, World!'\n"
    type     = "S3"
    location = "${aws_s3_bucket.primary_source_bucket.bucket}/source.zip"
  }

  secondary_sources {
    source_identifier = "secondary_source_one"
    type              = "S3"
    location          = "${aws_s3_bucket.secondary_source_one_bucket.bucket}/source.zip"
  }

  secondary_sources {
    source_identifier = "secondary_source_two"
    type              = "S3"
    location          = "${aws_s3_bucket.secondary_source_two_bucket.bucket}/source.zip"
  }

  artifacts {
    type           = "S3"
    location       = aws_s3_bucket.artifact_bucket.bucket
    path           = "artifacts"
    namespace_type = "NONE"
    packaging      = "ZIP"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type         = "LINUX_CONTAINER"
  }
}

resource "aws_s3_bucket_public_access_block" "artifact_bucket_public_access" {
  bucket = aws_s3_bucket.artifact_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_server_side_encryption_configuration" "artifact_bucket_encryption" {
  bucket = aws_s3_bucket.artifact_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_versioning" "artifact_bucket_versioning" {
  bucket = aws_s3_bucket.artifact_bucket.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "primary_source_bucket_public_access" {
